// Simplified test of the fix

type diff struct {
	baseline interface{}
	count    int
	simSum   int
}

// IsTruthful simplified
func isTruthful(v interface{}) bool {
	if v == nil {
		return false
	}
	if s, ok := v.(string); ok {
		return len(s) > 0
	}
	return true
}

func howSimilarStrings(a, b string) int {
