	as, ok1 := a.(string)
	bs, ok2 := b.(string)
	if ok1 && ok2 {
		return howSimilarStrings(as, bs)
	}
	if ok1 != ok2 {
		return 0
	}
	return 0
}

// BUGGY version (original)
func (d *diff) addBuggy(v interface{}) *diff {
	if !isTruthful(v) {
		d.baseline = v
		d.count = 1
		d.simSum = 100
