package main

import (
	"fmt"
	"math"
)

// Simplified test of the fix

type diff struct {
	baseline interface{}
	count    int
	simSum   int
}

// IsTruthful simplified
func isTruthful(v interface{}) bool {
	if v == nil {
		return false
	}
	if s, ok := v.(string); ok {
		return len(s) > 0
	}
	return true
}

func howSimilarStrings(a, b string) int {
	if a == b {
		return 100
	}
	return 50 // simplified
}

func howSimilar(a, b interface{}) int {
	as, ok1 := a.(string)
	bs, ok2 := b.(string)
	if ok1 && ok2 {
		return howSimilarStrings(as, bs)
	}
	if ok1 != ok2 {
		return 0
	}
	return 0
}

// BUGGY version (original)
func (d *diff) addBuggy(v interface{}) *diff {
	if !isTruthful(v) {
		d.baseline = v
		d.count = 1
		d.simSum = 100
		return d
	}

	d.simSum += howSimilar(v, d.baseline)
	d.count++

	return d
}

// FIXED version
func (d *diff) addFixed(v interface{}) *diff {
	if d.count == 0 || !isTruthful(v) {
		d.baseline = v
		d.count = 1
		d.simSum = 100
		return d
	}

	d.simSum += howSimilar(v, d.baseline)
	d.count++

	return d
}

func cacheFactor(d *diff) int {
	if d.count == 0 {
		return 0
	}
	return int(math.Floor(float64(d.simSum) / float64(d.count)))
}

func main() {
	fmt.Println("=== BUGGY VERSION ===")
	{
		d := &diff{}
		d.addBuggy("Hello World")
		d.addBuggy("Hello World")
		d.addBuggy("Hello World")
		cf := cacheFactor(d)
		fmt.Printf("3x same truthful string: cacheFactor=%d (expected ~100, got %d)\n", cf, cf)
		if cf == 0 {
			fmt.Println("  BUG: Cache factor is 0 even though all values are identical!")
		}
	}

	fmt.Println()
	fmt.Println("=== FIXED VERSION ===")
	{
		d := &diff{}
		d.addFixed("Hello World")
		d.addFixed("Hello World")
		d.addFixed("Hello World")
		cf := cacheFactor(d)
		fmt.Printf("3x same truthful string: cacheFactor=%d (expected ~100)\n", cf)
		if cf > 0 {
			fmt.Println("  FIXED: Cache factor correctly reflects similar values!")
		}
	}

	fmt.Println()
	fmt.Println("=== EDGE CASES (FIXED) ===")
	{
		// Non-truthful first value
		d := &diff{}
		d.addFixed("")
		cf := cacheFactor(d)
		fmt.Printf("1x empty string (non-truthful): cacheFactor=%d (expected 100)\n", cf)
	}
	{
		// Non-truthful first, then truthful
		d := &diff{}
		d.addFixed("")
		d.addFixed("Hello World")
		cf := cacheFactor(d)
		fmt.Printf("empty then 'Hello World': cacheFactor=%d\n", cf)
	}
	{
		// Single truthful value
		d := &diff{}
		d.addFixed("Single Value")
		cf := cacheFactor(d)
		fmt.Printf("1x truthful string: cacheFactor=%d (expected 100)\n", cf)
	}
}
EOF
